mapper.select:
SELECT c.*, v.name AS visitor_name, v.phone AS visitor_phone, v.id_card AS visitor_id_card, r.rating AS review_rating, r.content AS review_content, r.create_time AS review_time, r.reply AS review_reply, r.reply_time AS review_reply_time, r.id AS review_id FROM biz_check_in c LEFT JOIN biz_visitor v ON c.visitor_id = v.id LEFT JOIN biz_review r ON c.id = r.check_in_id AND r.deleted = 0 WHERE c.deleted = 0
AND visitor_id IN (SELECT id FROM biz_visitor WHERE name LIKE CONCAT('%', #{params.visitorName}, '%'))
AND room_no LIKE CONCAT('%', #{params.roomNo}, '%')
AND check_in_status = #{params.status}
AND payment_status = #{params.paymentStatus}
AND check_in_date >= #{params.startDate}
AND check_in_date <= #{params.endDate}
ORDER BY create_time DESC

SELECT c.*, v.name AS visitor_name, v.phone AS visitor_phone, v.id_card AS visitor_id_card FROM biz_check_in c LEFT JOIN biz_visitor v ON c.visitor_id = v.id WHERE c.deleted = 0
AND c.check_in_status = #{status}
ORDER BY c.create_time DESC
